print("Building Complex Material Library...")

def torch_interp(x_new, x_old, y_old):
    idx = torch.searchsorted(x_old, x_new).clamp(1, len(x_old) - 1)
    x_lo, x_hi = x_old[idx-1], x_old[idx]
    y_lo, y_hi = y_old[idx-1], y_old[idx]
    slope = (y_hi - y_lo) / (x_hi - x_lo)
    return y_lo + slope * (x_new - x_lo)

