mat1 = torch.complex(mat1_n, torch.zeros_like(mat1_n)) 

# Material 2: Al2O3 Medium Index)
r_al2o3_interp = np.interp(w_target_np, w_al2o3, r_al2o3)


mat2 = torch.complex(
    torch.tensor(r_al2o3_interp, dtype=torch.float32, device=device), 
    torch.zeros(1000, dtype=torch.float32, device=device)
)

MATERIAL_LIBRARY = torch.stack([mat0, mat1, mat2])
NUM_MATERIALS = MATERIAL_LIBRARY.shape[0]

# =====================================================================
# 4. UNIVERSAL PHYSICS ENGINE (OBLIQUE + TE/TM + COMPLEX + TOPOLOGY)
# =====================================================================
def calculate_art_torch(thicknesses, mat_logits, wavelengths, angle_deg=0.0, is_discrete=False):
    n_inc = 1.0  # Air
    n_sub = 1.5  # Glass Substrate
    
    angle_rad = torch.tensor(angle_deg * (np.pi / 180.0), device=device)
    sin_theta_inc = torch.sin(angle_rad).to(torch.complex64)
    cos_theta_inc = torch.cos(angle_rad).to(torch.complex64)
    
    if is_discrete:
        chosen_indices = torch.argmax(mat_logits, dim=1)
        weights = torch.nn.functional.one_hot(chosen_indices, num_classes=NUM_MATERIALS).float()
    else:
        weights = torch.softmax(mat_logits, dim=1) 
        
    n_layers = torch.matmul(weights.to(torch.complex64), MATERIAL_LIBRARY)
    
    M_total_TE = torch.eye(2, dtype=torch.complex64, device=device).unsqueeze(-1).repeat(1, 1, len(wavelengths))
    M_total_TM = torch.eye(2, dtype=torch.complex64, device=device).unsqueeze(-1).repeat(1, 1, len(wavelengths))

    for i in range(len(thicknesses)):
        n_l = n_layers[i] 
        d_l = thicknesses[i]
        
        sin_theta_l = (n_inc * sin_theta_inc) / n_l
        cos_theta_l = torch.sqrt(1.0 - sin_theta_l**2)
        
        phi = (2 * torch.pi * n_l * d_l * cos_theta_l) / wavelengths
        cos_p = torch.cos(phi)
        sin_p = torch.sin(phi)
        
        Y_TE = n_l * cos_theta_l
        Y_TM = n_l / cos_theta_l
        
        M_layer_TE = torch.stack([
            torch.stack([cos_p, 1j * sin_p / Y_TE]), 
            torch.stack([1j * Y_TE * sin_p, cos_p])
        ])
        M_total_TE = torch.einsum('ijk,jlk->ilk', M_total_TE, M_layer_TE)
        
        M_layer_TM = torch.stack([
            torch.stack([cos_p, 1j * sin_p / Y_TM]), 
            torch.stack([1j * Y_TM * sin_p, cos_p])
        ])
        M_total_TM = torch.einsum('ijk,jlk->ilk', M_total_TM, M_layer_TM)

    sin_theta_sub = (n_inc * sin_theta_inc) / n_sub
    cos_theta_sub = torch.sqrt(1.0 - sin_theta_sub**2)
    
    Y0_TE = n_inc * cos_theta_inc
    Y0_TM = n_inc / cos_theta_inc
    Ysub_TE = n_sub * cos_theta_sub
    Ysub_TM = n_sub / cos_theta_sub
    
    m11, m12, m21, m22 = M_total_TE[0,0], M_total_TE[0,1], M_total_TE[1,0], M_total_TE[1,1]
    denom_TE = (Y0_TE * m11 + Y0_TE * Ysub_TE * m12 + m21 + Ysub_TE * m22)
    T_TE = (torch.real(Ysub_TE) / torch.real(Y0_TE)) * torch.abs(2 * Y0_TE / denom_TE)**2
    
    m11, m12, m21, m22 = M_total_TM[0,0], M_total_TM[0,1], M_total_TM[1,0], M_total_TM[1,1]
    denom_TM = (Y0_TM * m11 + Y0_TM * Ysub_TM * m12 + m21 + Ysub_TM * m22)
    T_TM = (torch.real(Ysub_TM) / torch.real(Y0_TM)) * torch.abs(2 * Y0_TM / denom_TM)**2
    
    return (T_TE + T_TM) / 2.0

# =====================================================================
# 5. TARGETS & HYBRID LOSS FUNCTION
# =====================================================================
vis_mask = (wavelengths >= 400) & (wavelengths <= 750)
stop_mask = ~vis_mask

def calculate_hybrid_loss(thicknesses, mat_logits, apply_barrier=False, is_discrete=False):
    # Optimizing for normal incidence (0 degrees)
    T = calculate_art_torch(thicknesses, mat_logits, wavelengths, angle_deg=0.0, is_discrete=is_discrete)
    
    T_vis = T[vis_mask]
    T_stop = T[stop_mask]
    
    loss_passband = torch.mean((T_vis - 0.90)**2) * 15.0
    loss_stopband = torch.mean((T_stop - 0.15)**2) * 25.0
    flatness_penalty = torch.mean(torch.abs(T_vis[1:] - T_vis[:-1])) * 5.0
    thick_penalty = torch.clamp(torch.sum(thicknesses) - 3500, min=0) * 0.1
    
    total_loss = loss_passband + loss_stopband + flatness_penalty + thick_penalty
    
    # We apply this penalty only during continuous optimization, not final evaluation
    if not is_discrete:
        weights = torch.softmax(mat_logits, dim=1) 
        
        # Multiply adjacent layer weights element-wise. 
        # If Layer 1 is 99% SiO2 and Layer 2 is 99% SiO2, the overlap is huge (~1.0).
        # We sum this overlap and multiply by a massive penalty weight.
        overlap = torch.sum(weights[:-1] * weights[1:]) 
        clump_penalty = overlap * 200.0 
        
        total_loss += clump_penalty
        
    if apply_barrier:
        barrier_low = torch.sum(torch.relu(15.0 - thicknesses)**2) * 1000.0
        barrier_high = torch.sum(torch.relu(thicknesses - 800.0)**2) * 1000.0
        total_loss += (barrier_low + barrier_high)
        
    return total_loss

# =====================================================================
# PHASE 1: PSO Global Topology Search (RANDOM START)
# =====================================================================
print("\n--- PHASE 1: PSO Global Topology Search (Random Start) ---")
num_particles = 100
pso_iterations = 400
num_layers = 45

# 1. Initialize random swarm
# We start thicknesses safely within the 15nm to 150nm range
pos_t = torch.empty(num_particles, num_layers, device=device).uniform_(20.0, 150.0)
vel_t = torch.empty(num_particles, num_layers, device=device).uniform_(-10.0, 10.0)

# Initialize material logits completely neutral so the AI has no biases
pos_m = torch.empty(num_particles, num_layers, NUM_MATERIALS, device=device).uniform_(-1.0, 1.0)
vel_m = torch.empty(num_particles, num_layers, NUM_MATERIALS, device=device).uniform_(-0.5, 0.5)

# 2. Setup best trackers
p_best_pos_t = pos_t.clone()
p_best_pos_m = pos_m.clone()
p_best_scores = torch.full((num_particles,), float('inf'), device=device)

g_best_pos_t = torch.zeros(num_layers, device=device)
g_best_pos_m = torch.zeros(num_layers, NUM_MATERIALS, device=device)
g_best_score = torch.tensor(float('inf'), device=device)

w_pso, c1, c2 = 0.7, 1.5, 1.5

for iteration in range(pso_iterations):
    for i in range(num_particles):
        # Updated fail-state check to match the 15.0nm hardware limit
        if torch.any(pos_t[i] < 15.0):
            score = torch.tensor(float('inf'), device=device)
        else:
            score = calculate_hybrid_loss(pos_t[i], pos_m[i])
            
        if score < p_best_scores[i]:
            p_best_scores[i] = score
            p_best_pos_t[i] = pos_t[i].clone()
            p_best_pos_m[i] = pos_m[i].clone()
            if score < g_best_score:
                g_best_score = score
                g_best_pos_t = pos_t[i].clone()
                g_best_pos_m = pos_m[i].clone()
                
    r1, r2 = torch.rand(num_particles, 1, device=device), torch.rand(num_particles, 1, device=device)
    vel_t = (w_pso * vel_t) + (c1 * r1 * (p_best_pos_t - pos_t)) + (c2 * r2 * (g_best_pos_t.unsqueeze(0) - pos_t))
    pos_t = pos_t + vel_t
    
    # Enforce strict hardware limits
    pos_t.clamp_(min=15.0, max=800.0) 
    
    r1_m, r2_m = torch.rand(num_particles, 1, 1, device=device), torch.rand(num_particles, 1, 1, device=device)
    vel_m = (w_pso * vel_m) + (c1 * r1_m * (p_best_pos_m - pos_m)) + (c2 * r2_m * (g_best_pos_m.unsqueeze(0) - pos_m))
    pos_m = pos_m + vel_m
    pos_m.clamp_(min=-10.0, max=10.0) 
    
    if iteration % 50 == 0:
        print(f"PSO Iteration {iteration:3d}/{pso_iterations} | Best Score: {g_best_score.item():.4f}")

# =====================================================================
# PHASE 2: L-BFGS OPTIMIZATION (SURGICAL LOCAL SEARCH)
# =====================================================================
print("\n--- PHASE 2: L-BFGS Local Fine-Tuning ---")

d_param = nn.Parameter(g_best_pos_t.clone().detach())
m_param = nn.Parameter(g_best_pos_m.clone().detach())

# FIX 1: Add strong_wolfe line search and slightly lower learning rate
optimizer = optim.LBFGS([d_param, m_param], 
                        lr=0.05, 
                        max_iter=20, 
                        max_eval=25, 
                        line_search_fn="strong_wolfe")

lbfgs_steps = 15

for step in range(lbfgs_steps):
    def closure():
        optimizer.zero_grad()
        
        # FIX 2: Protect the physics engine! 
        # We clamp a TEMPORARY copy of the parameters just for the math so cosh() never overflows.
        safe_d = torch.clamp(d_param, min=15.0, max=800.0)
        safe_m = torch.clamp(m_param, min=-10.0, max=10.0)
        
        # Calculate loss using the safe variables
        loss = calculate_hybrid_loss(safe_d, safe_m, apply_barrier=False, is_discrete=False)
        
        # FIX 3: Apply boundary penalties to the RAW parameters.
        # This creates a steep "gradient wall" that naturally pushes the optimizer 
        # back into bounds without corrupting its Hessian memory.
        penalty_d_low = torch.sum(torch.relu(15.0 - d_param)**2) * 1000.0
        penalty_d_high = torch.sum(torch.relu(d_param - 800.0)**2) * 1000.0
        loss += penalty_d_low + penalty_d_high
        
        loss.backward()
        return loss

    loss = optimizer.step(closure)
    
    # Notice we REMOVED the manual d_param.clamp_() from here!
        
    print(f"L-BFGS Step {step + 1}/{lbfgs_steps} | Loss: {loss.item():.4f}")

# =====================================================================
# FINAL EXPORT & DISCRETIZATION
# =====================================================================
print("\n--- Hybrid Topology Optimization Complete! ---")

# Guarantee final export values are within physical bounds
final_d = torch.clamp(d_param.detach(), 15.0, 800.0).cpu().numpy()
final_m_logits = torch.clamp(m_param.detach(), -10.0, 10.0)

# Snap to discrete materials for real-world fabrication
final_mat_choices = torch.argmax(final_m_logits, dim=1).cpu().numpy()

# Calculate true physical spectrum with snapped materials
final_T = calculate_art_torch(torch.tensor(final_d, device=device), final_m_logits, wavelengths, angle_deg=0.0, is_discrete=True)

with torch.no_grad():
    T_vis = final_T[vis_mask]
    T_stop = final_T[stop_mask]
    rms_vis = torch.sqrt(torch.mean((T_vis - 1.0)**2)).item()
    mean_leak = torch.mean(T_stop).item()
    max_leak = torch.max(T_stop).item()

print(f"\nFinal Discrete Vis RMS: {rms_vis:.4f}")
print(f"Final Discrete IR Mean Leakage: {mean_leak:.4f}")
print(f"Final Discrete IR Max Leakage: {max_leak:.4f}")
print(f"Total Stack Thickness: {np.sum(final_d):.1f} nm")

mat_names = {0: "SiO2", 1: "TiO2", 2: "Al2O3"}

print("\nLayer-by-Layer Configuration:")
for i in range(num_layers):
    mat_idx = final_mat_choices[i]
    print(f"Layer {i+1:02d}: {mat_names.get(mat_idx, f'Mat {mat_idx}')} | Thickness: {final_d[i]:.1f} nm")

# Save outputs
np.savetxt('optimized_thicknesses_topo_4.txt', final_d, fmt='%.2f', header=f'{num_layers}-Layer Thicknesses (nm)')
np.savetxt('optimized_materials_topo_4.txt', final_mat_choices, fmt='%d', header='Material Indices (0=SiO2, 1=TiO2, 2=Al2O3)')
np.savetxt('final_spectrum_topo_4.csv', final_T.cpu().detach().numpy(), delimiter=',')

print("\nFiles saved successfully. Ready for analysis.")